   289→
   290→ScopedResume GrpcMuxImpl::pause(const std::vector<std::string> type_urls) {
   291→  for (const auto& type_url : type_urls) {
   292→    ApiState& api_state = apiStateFor(type_url);
   293→    ENVOY_LOG(debug, "Pausing discovery requests for {} (previous count {})", type_url,
   294→              api_state.pauses_);
   295→    ++api_state.pauses_;
   296→  }
   297→  return std::make_unique<Cleanup>([this, type_urls]() {
   298→    for (const auto& type_url : type_urls) {
   299→      ApiState& api_state = apiStateFor(type_url);
   300→      ENVOY_LOG(debug, "Decreasing pause count on discovery requests for {} (previous count {})",
   301→                type_url, api_state.pauses_);
   302→      ASSERT(api_state.paused());
   303→
   304→      if (--api_state.pauses_ == 0 && api_state.pending_ && api_state.subscribed_) {
   305→        ENVOY_LOG(debug, "Resuming discovery requests for {}", type_url);
   306→        queueDiscoveryRequest(type_url);
   307→        api_state.pending_ = false;
   308→      }
   309→    }
   310→  });
   311→}
